import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder rawInput = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            rawInput.append(line).append('\n');
        }
        // Convert escaped "\n" sequences to actual newlines
        String processed = rawInput.toString().replace("\\n", "\n");
        Scanner sc = new Scanner(processed);
        StringBuilder output = new StringBuilder();
        if (!sc.hasNextInt()) {
            System.out.print("");
            return;
        }
        int T = sc.nextInt();
        for (int tc = 0; tc < T; tc++) {
            int n = sc.nextInt();
            int k = sc.nextInt();
            String s = sc.next();
            int[] freq = new int[256];
            for (int i = 0; i < s.length(); i++) {
                freq[s.charAt(i)]++;
            }
            for (int i = 0; i < 256; i++) {
                if (freq[i] >= k) {
                    output.append((char) i);
                }
            }
            if (tc != T - 1) output.append('\n');
        }
        System.out.print(output.toString());
    }
}

